import{c as e,Q as l,j as a,m as n}from"./chunks/framework.CQqJojvj.js";const p=JSON.parse('{"title":"04 - MySQL","description":"","frontmatter":{},"headers":[],"relativePath":"bagu/04-mysql.md","filePath":"bagu/04-mysql.md","lastUpdated":null}'),s={name:"bagu/04-mysql.md"};function i(r,t,d,o,g,c){return l(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="_04-mysql" tabindex="-1">04 - MySQL <a class="header-anchor" href="#_04-mysql" aria-label="Permalink to &quot;04 - MySQL&quot;">​</a></h1><blockquote><p>MySQL 是后端开发者的必修课。索引、事务、锁、日志、SQL 优化是面试的重中之重。</p></blockquote><hr><h2 id="_1-事务" tabindex="-1">1. 事务 <a class="header-anchor" href="#_1-事务" aria-label="Permalink to &quot;1. 事务&quot;">​</a></h2><h3 id="acid-特性" tabindex="-1">ACID 特性 <a class="header-anchor" href="#acid-特性" aria-label="Permalink to &quot;ACID 特性&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">含义</th><th style="text-align:left;">实现方式</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>A</strong>tomicity（原子性）</td><td style="text-align:left;">事务是最小执行单元，不可分割</td><td style="text-align:left;">Undo Log（回滚日志）</td></tr><tr><td style="text-align:left;"><strong>C</strong>onsistency（一致性）</td><td style="text-align:left;">事务前后数据完整性约束不变</td><td style="text-align:left;">由其他三个特性共同保证</td></tr><tr><td style="text-align:left;"><strong>I</strong>solation（隔离性）</td><td style="text-align:left;">并发事务间互不干扰</td><td style="text-align:left;">MVCC + 锁</td></tr><tr><td style="text-align:left;"><strong>D</strong>urability（持久性）</td><td style="text-align:left;">事务提交后数据永久保存</td><td style="text-align:left;">Redo Log（重做日志）</td></tr></tbody></table><h3 id="并发事务带来的问题" tabindex="-1">并发事务带来的问题 <a class="header-anchor" href="#并发事务带来的问题" aria-label="Permalink to &quot;并发事务带来的问题&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">问题</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>脏读</strong></td><td style="text-align:left;">读到其他事务未提交的数据</td></tr><tr><td style="text-align:left;"><strong>不可重复读</strong></td><td style="text-align:left;">同一事务内两次读取同一条数据，结果不同（被其他事务 update 并提交）</td></tr><tr><td style="text-align:left;"><strong>幻读</strong></td><td style="text-align:left;">同一事务内两次查询，结果集行数不同（被其他事务 insert/delete 并提交）</td></tr></tbody></table><h3 id="四种隔离级别" tabindex="-1">四种隔离级别 <a class="header-anchor" href="#四种隔离级别" aria-label="Permalink to &quot;四种隔离级别&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">级别</th><th style="text-align:center;">脏读</th><th style="text-align:center;">不可重复读</th><th style="text-align:center;">幻读</th><th style="text-align:left;">实现</th></tr></thead><tbody><tr><td style="text-align:left;">READ UNCOMMITTED</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:left;">无锁</td></tr><tr><td style="text-align:left;">READ COMMITTED</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:left;">每次读取生成 ReadView</td></tr><tr><td style="text-align:left;">REPEATABLE READ（默认）</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌（大部分）</td><td style="text-align:left;">事务开始时生成 ReadView</td></tr><tr><td style="text-align:left;">SERIALIZABLE</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:left;">读写都加锁</td></tr></tbody></table><p><strong>InnoDB 在 RR 级别下如何解决幻读？</strong></p><ol><li><strong>MVCC（快照读）：</strong> 普通 SELECT 通过 ReadView 读快照，看不到其他事务插入的数据</li><li><strong>Next-Key Lock（当前读）：</strong> <code>SELECT ... FOR UPDATE</code> 等当前读，通过间隙锁（Gap Lock）+ 行锁（Record Lock）阻止其他事务插入</li></ol><hr><h2 id="_2-mvcc-多版本并发控制" tabindex="-1">2. MVCC（多版本并发控制） <a class="header-anchor" href="#_2-mvcc-多版本并发控制" aria-label="Permalink to &quot;2. MVCC（多版本并发控制）&quot;">​</a></h2><h3 id="实现原理" tabindex="-1">实现原理 <a class="header-anchor" href="#实现原理" aria-label="Permalink to &quot;实现原理&quot;">​</a></h3><p>MVCC 通过 ReadView + Undo Log 实现非锁定的一致性读。</p><p><strong>隐藏字段：</strong></p><ul><li><code>DB_TRX_ID</code> — 最后修改该行的事务 ID（6 bytes）</li><li><code>DB_ROLL_PTR</code> — 回滚指针，指向 Undo Log（7 bytes）</li><li><code>DB_ROW_ID</code> — 隐藏主键（6 bytes，当没有显式主键时）</li></ul><p><strong>ReadView 判断规则：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前事务 ID = cur_trx_id</span></span>
<span class="line"><span></span></span>
<span class="line"><span>遍历所有活跃事务，找到：</span></span>
<span class="line"><span>  - min_trx_id = 最小活跃事务 ID</span></span>
<span class="line"><span>  - max_trx_id = 最大活跃事务 ID + 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每行数据 trx_id 的判断：</span></span>
<span class="line"><span>  - trx_id &lt; min_trx_id  → 可见（在 ReadView 创建前已提交）</span></span>
<span class="line"><span>  - trx_id &gt;= max_trx_id → 不可见（在 ReadView 创建后新开的事务）</span></span>
<span class="line"><span>  - 在两者之间 → 判断 trx_id 是否在活跃列表中</span></span>
<span class="line"><span>      - 在活跃列表中 → 不可见</span></span>
<span class="line"><span>      - 不在活跃列表中 → 可见</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p><strong>RC vs RR 的 ReadView 区别：</strong></p><ul><li>RC：<strong>每次 SELECT</strong> 都生成新的 ReadView</li><li>RR：<strong>事务开始时</strong>生成一次 ReadView，后续复用</li></ul><hr><h2 id="_3-索引" tabindex="-1">3. 索引 <a class="header-anchor" href="#_3-索引" aria-label="Permalink to &quot;3. 索引&quot;">​</a></h2><h3 id="b-树索引" tabindex="-1">B+树索引 <a class="header-anchor" href="#b-树索引" aria-label="Permalink to &quot;B+树索引&quot;">​</a></h3><p><strong>为什么不用其他数据结构？</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">数据结构</th><th style="text-align:left;">不适合的原因</th></tr></thead><tbody><tr><td style="text-align:left;">哈希表</td><td style="text-align:left;">范围查询效率低；无法排序</td></tr><tr><td style="text-align:left;">二叉搜索树</td><td style="text-align:left;">可能退化为链表（O(n)）；深度太大导致大量磁盘 IO</td></tr><tr><td style="text-align:left;">B树</td><td style="text-align:left;">非叶子节点存储数据，导致每页存储的索引条目少，树更高</td></tr><tr><td style="text-align:left;">红黑树</td><td style="text-align:left;">二叉树变种，深度仍然大</td></tr></tbody></table><p><strong>B+树的优势：</strong></p><ol><li>非叶子节点只存键值，每页可存更多索引，树更矮（减少磁盘 IO）</li><li>叶子节点通过双向链表连接，支持高效范围查询</li><li>数据只存储在叶子节点，查询效率稳定</li></ol><h3 id="聚簇索引-vs-非聚簇索引" tabindex="-1">聚簇索引 vs 非聚簇索引 <a class="header-anchor" href="#聚簇索引-vs-非聚簇索引" aria-label="Permalink to &quot;聚簇索引 vs 非聚簇索引&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">叶子节点存储</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>聚簇索引</strong>（主键索引）</td><td style="text-align:left;">完整行数据</td><td style="text-align:left;">一张表只有一个；InnoDB 自动按主键聚集</td></tr><tr><td style="text-align:left;"><strong>非聚簇索引</strong>（二级索引）</td><td style="text-align:left;">主键值</td><td style="text-align:left;">需要回表查主键索引获取完整行数据</td></tr><tr><td style="text-align:left;"><strong>覆盖索引</strong></td><td style="text-align:left;">—</td><td style="text-align:left;">查询列都在索引中，不需要回表</td></tr></tbody></table><p><strong>回表：</strong> 二级索引找到主键，再用主键去聚簇索引找完整记录。避免回表的方式是使用覆盖索引。</p><h3 id="索引失效的情况" tabindex="-1">索引失效的情况 <a class="header-anchor" href="#索引失效的情况" aria-label="Permalink to &quot;索引失效的情况&quot;">​</a></h3><ol><li><strong>LIKE 前置模糊</strong> — <code>LIKE &#39;%xxx&#39;</code> 无法使用索引</li><li><strong>WHERE 中使用函数/表达式</strong> — <code>WHERE YEAR(create_time) = 2024</code></li><li><strong>隐式类型转换</strong> — <code>WHERE phone = 13800000000</code>（phone 是 varchar）</li><li><strong>OR 条件中有非索引列</strong> — 每个 OR 分支都需要用索引才行</li><li><strong>NOT IN / NOT EXISTS / != / &lt;&gt;</strong> — 大多数情况下不会走索引</li><li><strong>联合索引不满足最左前缀</strong> — <code>INDEX(a, b, c)</code> 中查询 <code>b = ?</code> 不走索引</li><li><strong>范围查询右侧的列失效</strong> — <code>WHERE a = 1 AND b &gt; 10 AND c = 3</code>（c 不走索引）</li><li><strong>查询基数太小</strong> — 优化器认为全表扫描更快（如性别字段）</li></ol><hr><h2 id="_4-日志系统" tabindex="-1">4. 日志系统 <a class="header-anchor" href="#_4-日志系统" aria-label="Permalink to &quot;4. 日志系统&quot;">​</a></h2><h3 id="redo-log-重做日志" tabindex="-1">Redo Log（重做日志） <a class="header-anchor" href="#redo-log-重做日志" aria-label="Permalink to &quot;Redo Log（重做日志）&quot;">​</a></h3><ul><li><strong>作用：</strong> 保证事务的持久性，crash-safe</li><li><strong>记录内容：</strong> 物理日志，记录&quot;在某页的某个位置做了什么修改&quot;</li><li><strong>写入方式：</strong> 循环写（write pos 和 checkpoint 之间的空间可用）</li><li><strong>刷盘策略（<code>innodb_flush_log_at_trx_commit</code>）：</strong><ul><li><code>0</code> — 每秒刷盘（可能丢1秒数据）</li><li><code>1</code> — 每次提交刷盘（最安全）✅ 推荐</li><li><code>2</code> — 每次提交写 page cache，每秒刷盘（OS 崩溃可能丢）</li></ul></li></ul><h3 id="undo-log-回滚日志" tabindex="-1">Undo Log（回滚日志） <a class="header-anchor" href="#undo-log-回滚日志" aria-label="Permalink to &quot;Undo Log（回滚日志）&quot;">​</a></h3><ul><li><strong>作用：</strong> 事务回滚 + MVCC 读历史版本</li><li><strong>记录内容：</strong> 逻辑日志，记录数据修改前的值</li><li><strong>生命周期：</strong> 事务提交后不立即删除，直到没有其他事务需要它</li></ul><h3 id="binlog-归档日志" tabindex="-1">BinLog（归档日志） <a class="header-anchor" href="#binlog-归档日志" aria-label="Permalink to &quot;BinLog（归档日志）&quot;">​</a></h3><ul><li><strong>作用：</strong> 主从复制 + 数据恢复</li><li><strong>记录内容：</strong> 逻辑日志，记录 SQL 语句或行变更</li><li><strong>写入方式：</strong> 追加写，文件写满切换</li><li><strong>刷盘策略（<code>sync_binlog</code>）：</strong><ul><li><code>0</code> — 由 OS 决定刷盘时机</li><li><code>1</code> — 每次提交刷盘 ✅ 推荐</li><li><code>N</code> — 每 N 次提交刷盘</li></ul></li></ul><h3 id="两阶段提交-2pc" tabindex="-1">两阶段提交（2PC） <a class="header-anchor" href="#两阶段提交-2pc" aria-label="Permalink to &quot;两阶段提交（2PC）&quot;">​</a></h3><p>Redo Log 和 BinLog 通过两阶段提交保证一致性：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Prepare Phase    → Redo Log 写 prepare 状态</span></span>
<span class="line"><span>2. Commit Phase     → BinLog 写入并刷盘</span></span>
<span class="line"><span>3.                  → Redo Log 写 commit 状态</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>崩溃恢复时：如果 Redo Log 是 prepare 状态且有对应的 BinLog → 提交；如果没有 BinLog → 回滚。</p><hr><h2 id="_5-锁" tabindex="-1">5. 锁 <a class="header-anchor" href="#_5-锁" aria-label="Permalink to &quot;5. 锁&quot;">​</a></h2><h3 id="锁的类型" tabindex="-1">锁的类型 <a class="header-anchor" href="#锁的类型" aria-label="Permalink to &quot;锁的类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">类型</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">锁粒度</td><td style="text-align:left;">表锁 / 行锁</td><td style="text-align:left;">InnoDB 支持行锁，MyISAM 仅支持表锁</td></tr><tr><td style="text-align:left;">锁模式</td><td style="text-align:left;">共享锁(S) / 排他锁(X)</td><td style="text-align:left;">S 锁兼容 S 锁，其他互斥</td></tr><tr><td style="text-align:left;">意向锁</td><td style="text-align:left;">IS / IX</td><td style="text-align:left;">表级锁，表示有行级 S/X 锁，用于判断表中是否有锁</td></tr><tr><td style="text-align:left;">间隙锁</td><td style="text-align:left;">Gap Lock</td><td style="text-align:left;">锁定索引间隙，防止插入</td></tr><tr><td style="text-align:left;">临键锁</td><td style="text-align:left;">Next-Key Lock</td><td style="text-align:left;">Record Lock + Gap Lock，左开右闭区间</td></tr><tr><td style="text-align:left;">插入意向锁</td><td style="text-align:left;">Insert Intention Lock</td><td style="text-align:left;">INSERT 时在间隙上设置的锁</td></tr></tbody></table><h3 id="innodb-加锁规则" tabindex="-1">InnoDB 加锁规则 <a class="header-anchor" href="#innodb-加锁规则" aria-label="Permalink to &quot;InnoDB 加锁规则&quot;">​</a></h3><ol><li>只有通过索引检索数据时，才使用行锁；否则升级为表锁</li><li>RR 级别下，等值查询会退化为 Record Lock（唯一索引命中时）或 Next-Key Lock</li><li>范围查询始终使用 Next-Key Lock</li></ol><hr><h2 id="_6-sql-优化" tabindex="-1">6. SQL 优化 <a class="header-anchor" href="#_6-sql-优化" aria-label="Permalink to &quot;6. SQL 优化&quot;">​</a></h2><h3 id="执行计划-explain" tabindex="-1">执行计划 EXPLAIN <a class="header-anchor" href="#执行计划-explain" aria-label="Permalink to &quot;执行计划 EXPLAIN&quot;">​</a></h3><p>关键字段：</p><table tabindex="0"><thead><tr><th style="text-align:left;">字段</th><th style="text-align:left;">说明</th><th style="text-align:left;">期望值</th></tr></thead><tbody><tr><td style="text-align:left;"><code>type</code></td><td style="text-align:left;">访问类型</td><td style="text-align:left;">system &gt; const &gt; eq_ref &gt; ref &gt; range &gt; index &gt; ALL</td></tr><tr><td style="text-align:left;"><code>key</code></td><td style="text-align:left;">实际使用的索引</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;"><code>rows</code></td><td style="text-align:left;">预估扫描行数</td><td style="text-align:left;">越小越好</td></tr><tr><td style="text-align:left;"><code>Extra</code></td><td style="text-align:left;">额外信息</td><td style="text-align:left;">避免 Using temporary, Using filesort</td></tr></tbody></table><h3 id="优化实战" tabindex="-1">优化实战 <a class="header-anchor" href="#优化实战" aria-label="Permalink to &quot;优化实战&quot;">​</a></h3><ol><li><strong>select * 能不用就不用</strong> — 减少网络传输，增加覆盖索引机会</li><li><strong>合理分页</strong> — 深分页用子查询/游标：<code>WHERE id &gt; (SELECT id FROM t LIMIT 100000, 1) LIMIT 20</code></li><li><strong>批量操作</strong> — INSERT INTO ... VALUES (...), (...), (...)</li><li><strong>JOIN 代替子查询</strong> — 小表驱动大表</li><li><strong>联合索引</strong> — 区分度高的字段放前面</li><li><strong>避免使用 <code>%</code> 前置模糊查询</strong> — 考虑用 Elasticsearch 等搜索引擎</li></ol><h3 id="慢查询分析流程" tabindex="-1">慢查询分析流程 <a class="header-anchor" href="#慢查询分析流程" aria-label="Permalink to &quot;慢查询分析流程&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 开启慢查询日志（slow_query_log）</span></span>
<span class="line"><span>2. 设置 long_query_time 阈值</span></span>
<span class="line"><span>3. EXPLAIN 分析执行计划</span></span>
<span class="line"><span>4. 查看 type/rows/Extra 定位问题</span></span>
<span class="line"><span>5. 优化索引 / 改写 SQL / 数据归档</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div>`,61)])])}const x=e(s,[["render",i]]);export{p as __pageData,x as default};
